let output = [];

// Access n8n's static workflow memory
const workflowStaticData = $getWorkflowStaticData('global');
if (!workflowStaticData.recentConversations) {
  workflowStaticData.recentConversations = {};
}

const now = Date.now();

for (let item of $input.all()) {
  const data = item.json.body || item.json;

  // 1. Loop prevention check
  if (data.message_type === 'outgoing' || data.message_type === 1) {
    continue; 
  }

  // 2. Safely extract identifiers first
  const accountId = data.account?.id || data.account_id;
  const conversationId = data.conversation?.id || data.conversation_id || data.id;

  // 3. DEDUPLICATION LOCK
  // If we have processed this specific conversation ID in the last 5 seconds, drop this duplicate execution
  if (conversationId) {
    const lastProcessedTime = workflowStaticData.recentConversations[conversationId];
    if (lastProcessedTime && (now - lastProcessedTime < 5000)) {
      continue; // Kill the duplicate execution right here
    }
    // Mark this ID as processed with the current timestamp
    workflowStaticData.recentConversations[conversationId] = now;
  }

  // 4. Extract content safely
  let rawContent = data.content || "";
  if (data.messages && data.messages.length > 0) {
    rawContent = data.messages[0].content || "";
  }

  // 5. Email form cleaning
  if (rawContent.includes("Message Body:")) {
    let parts = rawContent.split("Message Body:");
    let textAfterBody = parts[1] || "";
    let cleanQuestion = textAfterBody.split("--")[0];
    rawContent = cleanQuestion.trim();
  }

  // Map values downstream
  item.json.question = rawContent;
  item.json.accountId = accountId;
  item.json.conversationId = conversationId;

  output.push(item);
}

return output;

