const match = raw.match(/\"content\":\"(.*?)\",\"refusal\"/);
const answer = match ? match[1] : "Sorry, I could not generate an answer.";

// Grab the original event type straight from the Webhook trigger
const webhookData = $('Webhook').first().json;
const eventType = webhookData.body?.event || webhookData.event;

// KILL THE DUPLICATE: If this execution run was triggered by 'conversation_created', 
// stop it right here so it never passes an item to the final HTTP Request node.
